"use strict";const $=q=>document.querySelector(q),$$=q=>document.querySelectorAll(q);
function formatDate(d){return new Date(d).toLocaleString([], {hour:'2-digit',minute:'2-digit',day:'2-digit',month:'short'})}
function setClock(){const now=new Date();$('#clock').textContent=now.toLocaleString([], {weekday:'short', day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit'})}
async function loadArticles(){const res=await fetch('articles.json',{cache:'no-cache'});const data=await res.json();window.__ARTICLES__=data;return data}
function buildTicker(items){const wrap=$('.ticker .items');wrap.innerHTML='';const list=[...items].sort((a,b)=>new Date(b.published_at)-new Date(a.published_at)).slice(0,8);list.forEach(a=>{const el=document.createElement('span');el.innerHTML=`<span class="label">Breaking</span> ${a.title}`;wrap.appendChild(el)});wrap.innerHTML+=wrap.innerHTML}
function weatherIcon(code){const map={0:'☀️',1:'🌤️',2:'⛅',3:'☁️',45:'🌫️',48:'🌫️',51:'🌦️',61:'🌧️',63:'🌧️',65:'🌧️',71:'❄️',80:'🌧️',95:'⛈️'};return map[code]||'🌡️'}
async function loadWeather(){try{const r=await fetch('https://api.open-meteo.com/v1/forecast?latitude=53.6149&longitude=-2.1552&current_weather=true');const j=await r.json();const cw=j.current_weather;$('#weather').textContent=`${weatherIcon(cw.weathercode)} ${Math.round(cw.temperature)}°C • Rochdale`;}catch(e){$('#weather').textContent='Weather unavailable'}}
function cardHTML(a){const q=a.quotes?.[0]?`<div class="quote">“${a.quotes[0]}”</div>`:'';return `<article class="card">
<a href="post.html?slug=${encodeURIComponent(a.slug)}"><img loading="lazy" src="${a.image_url}" alt="${a.title}"></a>
<div class="body"><div class="meta">${a.area} • ${formatDate(a.published_at)} • <span class="badge">${a.types[0]||'news'}</span></div>
<h3><a href="post.html?slug=${encodeURIComponent(a.slug)}">${a.title}</a></h3><p>${a.excerpt}</p>${q}</div></article>`}
function renderHome(data){const main=$('.main');main.innerHTML=data.sort((a,b)=>new Date(b.published_at)-new Date(a.published_at)).map(cardHTML).join('')}
function setupSearch(data){const input=$('#search');const box=$('.search .results');function close(){box.style.display='none'}
input.addEventListener('input',()=>{const v=input.value.trim().toLowerCase();if(!v){close();return}const m=data.filter(a=>a.title.toLowerCase().includes(v)).slice(0,8);box.innerHTML=m.map(a=>`<a href="post.html?slug=${encodeURIComponent(a.slug)}">${a.title}</a>`).join('');box.style.display=m.length?'block':'none'});
input.addEventListener('focus',()=>{if(box.innerHTML) box.style.display='block'});document.addEventListener('click',(e)=>{if(!e.target.closest('.search')) close()})}
function readParam(name){return new URLSearchParams(location.search).get(name)}
function renderListPage(data){const area=readParam('area');const typ=readParam('type');let list=data;if(area) list=list.filter(a=>a.area.toLowerCase()===area.toLowerCase());if(typ) list=list.filter(a=>a.types.includes(typ));$('#page-title').textContent=area?`${area} news`:`${typ} news`;$('.main').innerHTML=list.sort((a,b)=>new Date(b.published_at)-new Date(a.published_at)).map(cardHTML).join('')}
function renderPost(data){const slug=readParam('slug');const a=data.find(x=>x.slug===slug);if(!a){$('.post').innerHTML='<p>Article not found.</p>';return}document.title=a.title+' • Rochdale Daily';$('#p-title').textContent=a.title;$('#p-meta').textContent=`${a.area} • ${formatDate(a.published_at)} • ${(a.types||[]).join(', ')}`;$('#p-img').src=a.image_url;$('#p-img').alt=a.title;$('#p-body').innerHTML=a.content_html;const quotes=(a.quotes||[]).slice(0,3).map(q=>`<blockquote class="quote">“${q}”</blockquote>`).join('');$('#p-quotes').innerHTML=quotes}
document.addEventListener('DOMContentLoaded',async()=>{setClock();setInterval(setClock,60000);loadWeather();const data=await loadArticles();buildTicker(data.filter(a=>a.breaking));setupSearch(data);if(document.body.dataset.page==='home'){renderHome(data)}if(document.body.dataset.page==='list'){renderListPage(data)}if(document.body.dataset.page==='post'){renderPost(data)}});